-- Wrap-Up Happy Path — placeholder pictures for Partner, Lead Tutor, and Regular Tutor cells

update public.cells
set picture = '/blueprint-images/shared/step-visual-placeholder.svg'
where path_id = 'a0000000-0000-4000-8000-00000000080e'
  and id in (
    'a0000000-0000-4000-8000-0000001c0101',
    'a0000000-0000-4000-8000-0000001c0201',
    'a0000000-0000-4000-8000-0000001c0301',
    'a0000000-0000-4000-8000-0000001c0401',
    'a0000000-0000-4000-8000-0000001c0102',
    'a0000000-0000-4000-8000-0000001c0202',
    'a0000000-0000-4000-8000-0000001c0302',
    'a0000000-0000-4000-8000-0000001c0402',
    'a0000000-0000-4000-8000-0000001c0103',
    'a0000000-0000-4000-8000-0000001c0203',
    'a0000000-0000-4000-8000-0000001c0303',
    'a0000000-0000-4000-8000-0000001c0403'
  );
